const CHECK_PATH_DATA = 'M438.993,484.065 L505.168,549.282 L751.144,302.33';
const CHECK_STROKE_WIDTH = 56.507;

const MONOCHROME_PNG_BASE64 = '';
const FOREGROUND_PNG_BASE64 = '';
const BACKGROUND_PNG_BASE64 = '';

const formatPathNumber = (value) => Number(value.toFixed(3)).toString();

const buildVectorDrawableXml = () => `<?xml version="1.0" encoding="utf-8"?>
<vector xmlns:android="http://schemas.android.com/apk/res/android"
    android:width="108dp"
    android:height="108dp"
    android:viewportWidth="${SIZE}"
    android:viewportHeight="${SIZE}">
    <path
        android:pathData="${RING_PATH_DATA}"
        android:fillColor="#FFFFFFFF" />
    <path
        android:pathData="${CHECK_PATH_DATA}"
        android:fillColor="#00000000"
        android:strokeColor="#FFFFFFFF"
        android:strokeWidth="${formatPathNumber(CHECK_STROKE_WIDTH)}"
        android:strokeLineCap="round"
        android:strokeLineJoin="round" />
</vector>
`;

const writeBase64Png = (outputPath, data) => {
  fs.writeFileSync(outputPath, Buffer.from(data, 'base64'));
};

const generateIcon = () => {
  writeBase64Png(MONOCHROME_OUTPUT_PATH, MONOCHROME_PNG_BASE64);
  writeBase64Png(FOREGROUND_OUTPUT_PATH, FOREGROUND_PNG_BASE64);
  writeBase64Png(BACKGROUND_OUTPUT_PATH, BACKGROUND_PNG_BASE64);

  [MONOCHROME_OUTPUT_PATH, FOREGROUND_OUTPUT_PATH, BACKGROUND_OUTPUT_PATH].forEach((outputPath) => {
    console.log(`Generated ${path.relative(process.cwd(), outputPath)}`);
  });
};

if (require.main === module) {
  generateIcon();
}

module.exports = {
  buildVectorDrawableXml,
  __testables: {
    BACKGROUND_PNG_BASE64,
    CHECK_PATH_DATA,
    CHECK_STROKE_WIDTH,
    FOREGROUND_PNG_BASE64,
    MONOCHROME_PNG_BASE64,
    RING_PATH_DATA,
    formatPathNumber,
  },
};
